import{_ as r,o as n,c as i,ae as a,j as e}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Bing Ads","description":"","frontmatter":{"title":"Bing Ads","slug":"bing-ads"},"headers":[],"relativePath":"marketer-hub/bing-ads.md","filePath":"marketer-hub/bing-ads.md"}'),o={name:"marketer-hub/bing-ads.md"};function s(d,t,l,p,h,c){return n(),i("div",null,[...t[0]||(t[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://bingads.microsoft.com/" target="_blank" rel="noreferrer">Bing Ads</a> is a service that provides pay per click advertising on both the Bing and Yahoo! search engines.</p><p><strong>PARTNER CAPABILITIES</strong></p><table tabindex="0"><thead><tr><th>Partner Capabilities</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Ad Campaign Types</td><td>- Acquisition campaigns</td></tr><tr><td>Ad Formats</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Click Types</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Supported Platforms</td><td>- iOS - Android - Windows</td></tr><tr><td>Link Wrapping</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Cost Ingestion Support</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Cost Ingestion Types</td><td>Contact support at Bing Ads for more information.</td></tr><tr><td>Pricing Models</td><td>Contact support at Bing Ads for more information.</td></tr></tbody></table><h2 id="_1-complete-ads-prerequisites" tabindex="-1">1. Complete Ads Prerequisites <a class="header-anchor" href="#_1-complete-ads-prerequisites" aria-label="Permalink to &quot;1. Complete Ads Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">DEVELOPER MAY BE REQUIRED</p><p>The following Ads prerequisite includes providing URI schemes and other components that may require a developer:</p><ul><li><a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>Add Deep Link Routing &amp; Required Redirects</strong></a></li></ul></div><div class="warning custom-block"><p class="custom-block-title">DEVELOPER REQUIRED</p><p>The following Ads prerequisites involve app code changes:</p><ul><li><a href="./native-sdks-overview.html"><strong>Implement the Branch SDK</strong></a></li></ul></div><h2 id="_2-enable-the-integration" tabindex="-1">2. Enable the Integration <a class="header-anchor" href="#_2-enable-the-integration" aria-label="Permalink to &quot;2. Enable the Integration&quot;">​</a></h2><ol><li>Visit the <a href="https://dashboard.branch.io/ads" target="_blank" rel="noreferrer"><strong>Ads</strong></a> page on the Branch dashboard.</li><li>Select <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a> from the sidebar.</li><li>Search for Bing Ads.</li><li>Select <strong>Bing Ads</strong>, and click <strong>Save &amp; Enable</strong>.</li></ol><h2 id="_3-enable-postbacks" tabindex="-1">3. Enable Postbacks <a class="header-anchor" href="#_3-enable-postbacks" aria-label="Permalink to &quot;3. Enable Postbacks&quot;">​</a></h2><p>When Branch measures a conversion (install or other events), it determines which ad network or partner is responsible for generating the action, then attributes credit to the proper partner accordingly. Branch notifies the Ad partner of these events via postbacks which are turned on when you enable any Ads integrated partner.</p><p>Bing Ads only support the INSTALL postback.</p><p><em>[Image: 2060]</em></p><p>Bing Postbacks</p><div class="danger custom-block"><p class="custom-block-title">Troubleshoot Postbacks</p><p>There may be times when you need to reset a partner&#39;s settings; i.e. when a partner updates their postback templates or when perhaps you&#39;ve made a mistake during partner setup. Resetting a partner&#39;s settings allows you to re-enable the partner integration with the correct information to accurately measure and attribute conversion.</p><p>Note, by resetting your partner settings, this will:</p><ul><li>Disable the ad partner</li><li>Clear out all of your saved credentials and postbacks that are already setup</li><li>Return the ad partner to its basic configuration</li></ul><p><a href="./reset-my-ad-partners-settings.html">Learn more here on how to reset your ad partner&#39;s settings.</a></p></div><h2 id="_4-verify-integration-setup" tabindex="-1">4. Verify Integration Setup <a class="header-anchor" href="#_4-verify-integration-setup" aria-label="Permalink to &quot;4. Verify Integration Setup&quot;">​</a></h2><details><summary>View Link Parameters</summary><p>By default, Branch automatically appends partner-specific link parameters during the link creation process. When a user clicks on the link, Bing Ads provides the appropriate parameter values which Branch ingests and uses for attribution and reporting purposes.</p><p>Below are the link parameters that Branch automatically appends for this ad partner:</p></details><details><summary>View Attribution Windows</summary><p>Branch employs <a href="./attribution-windows-link-settings.html">Attribution Windows</a> at both the app level and the ad partner level. When you enable Bing Ads, Branch uses the attribution windows you&#39;ve selected at the app level.</p><p>However, you can choose to use the attribution windows provided specifically by Bing Ads. To do so, toggle the <strong>Use Ad Partner Attribution Windows</strong> to on. Please keep in mind that only conversions attributed to this ad partner will use these specific windows; otherwise, the app-level windows prevail.</p></details><details><summary>Test Postbacks</summary><p>Testing your configuration is a very important step that we highly recommend you take the time to complete before going live with marketing campaigns.</p><p>Learn how to <a href="./testing-postbacks.html">Test Postbacks</a></p></details><h2 id="_5-create-a-branch-link" tabindex="-1">5. Create a Branch Link <a class="header-anchor" href="#_5-create-a-branch-link" aria-label="Permalink to &quot;5. Create a Branch Link&quot;">​</a></h2><p>If you are running paid advertising campaigns, you&#39;ll want to create a Branch Ad Link so we can accurately attribute resulting app conversions to the appropriate advertising partner.</p><p>Branch Ad Links support deferred deep linking, Android App Links, and iOS Universal Links, as well as web and app conversions.</p><p>Learn how to <a href="./ad-links.html">Create A Branch Ad Link</a>.</p><div class="warning custom-block"><p class="custom-block-title">Bing App Extension Ads</p><p>When running Bing App Extension campaigns, you must run separate links for your Android and iOS app campaigns. In addition to that, for each platform&#39;s link, set the desktop redirect to the platform-specific App Store. For example, in your Android campaign link, set the desktop redirect to the app listing in the Play Store.</p></div><h2 id="using-branch-ad-links-in-bing-app-install-ads" tabindex="-1">Using Branch Ad links in Bing App Install Ads <a class="header-anchor" href="#using-branch-ad-links-in-bing-app-install-ads" aria-label="Permalink to &quot;Using Branch Ad links in Bing App Install Ads&quot;">​</a></h2><p>When creating an app install campaign on Bing Ads, it has options to enter the final URL and a tracking template. By default, it uses the store page URL of the app as the final URL, however, this needs to be replaced with a Branch Ad Link in a specific way;</p><p><strong>Example Branch Ad Link:</strong><br><code>https://branchster.app.link/UuR8XIPPljb?%243p=a_bing_ads&amp;~ad_id={AdId}&amp;~ad_set_id={AdGroupId}&amp;~ad_set_name={AdGroup}&amp;~campaign={Campaign}&amp;~campaign_id={CampaignId}&amp;~click_id={msclkid}&amp;~keyword={keyword:default}</code></p><p>Deconstructing the Branch Ad Link, we can obtain both the final URL and tracking template to run the app install campaign:</p>',28),e("table",{tabindex:"0"},[e("thead",null,[e("tr",null,[e("th",null,"Final URL"),e("th",null,"Tracking Template")])]),e("tbody",null,[e("tr",null,[e("td",null,"branchster.app.link/UuR8XIPPljb"),e("td",{"keyword:default":""},"{lpurl}?%243p=a_bing_ads&~ad_id={AdId}&~ad_set_id={AdGroupId}&~ad_set_name={AdGroup}&~campaign={Campaign}&~campaign_id={CampaignId}&~click_id={msclkid}&~keyword=")])])],-1),a('<h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>Bing prioritizes keyword-level final URLs over ad-level URLs, which results in Branch not being able to register the click, and users not being redirected by the Branch Link.</p><p>To address this issue, choose one of the following options:</p><ol><li><p>Remove the final URL at the keyword level, so that the Branch Link is used:</p><ul><li><code>www.example.com</code></li></ul></li><li><p>Apply the Branch Link at the keyword level instead of the ad level:</p><ul><li><code>example.app.link</code></li></ul></li></ol><p>Branch Links should be applied at the highest level of URL precedence (keyword, ad, or campaign).</p>',5)])])}const m=r(o,[["render",s]]);export{g as __pageData,m as default};
